import React, { useState, useEffect } from 'react';
import fishData from './FishData.json';

export default function KnowledgePage() {
    const [fishes, setFishes] = useState([]);

    useEffect(() => {
        setFishes(fishData.freshwater_fish_vietnam);
    }, []);

    return (
        <div className="main-content p-6 bg-gray-100 min-h-screen">
            <h1 className="text-3xl font-bold text-center mb-8 text-blue-800">
                Kiến thức về các loài cá nước ngọt Việt Nam
            </h1>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                {fishes.map((fish) => (
                    <div
                        key={fish.id}
                        className="bg-white rounded-lg shadow-lg overflow-hidden hover:shadow-xl transition-shadow duration-300"
                    >
                        <img
                            src={fish.image_url}
                            alt={fish.name}
                            className="w-full h-48 object-cover"
                            onError={(e) => {
                                e.target.src = 'https://via.placeholder.com/300x200?text=Image+Not+Found';
                            }}
                        />
                        <div className="p-4">
                            <h2 className="text-xl font-semibold text-blue-600 mb-2">{fish.name}</h2>
                            <p className="text-gray-700 text-sm mb-1">
                                <span className="font-medium">Đặc điểm:</span> {fish.characteristics.appearance}
                            </p>
                            <p className="text-gray-700 text-sm mb-1">
                                <span className="font-medium">Kích cỡ:</span> {fish.characteristics.size}
                            </p>
                            <p className="text-gray-700 text-sm mb-1">
                                <span className="font-medium">Tập tính:</span> {fish.behavior}
                            </p>
                            <p className="text-gray-700 text-sm mb-1">
                                <span className="font-medium">Mồi yêu thích:</span> {fish.favorite_bait}
                            </p>
                            <p className="text-gray-700 text-sm">
                                <span className="font-medium">Thông tin:</span> {fish.info}
                            </p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}
